```python
class ChannelSelection(BaseModel):
    channel: str

class UserSelection(BaseModel):
    user: str

class RestaurantLead(BaseModel):
    found: bool
    restaurant_name: str
    cuisine: str
    source_sender: str
    source_body: str
    restaurant_url: str

class CuisineInfo(BaseModel):
    cuisine: str

channels = get_channels()
if len(channels) == 0:
    raise ValueError("No channels found")

general_matches = [channel for channel in channels if channel.lower() == "general" or channel.lower() == "#general"]
if len(general_matches) == 1:
    general_channel = general_matches[0]
else:
    channel_choice = query_ai_assistant(
        "Select the exact Slack channel name from the following list that best matches the user's reference to the general channel. Return one exact channel string from the list.\nChannels: {}".format(repr(channels)),
        ChannelSelection,
    )
    general_channel = channel_choice.channel

if general_channel not in channels:
    raise ValueError("General channel not found")

messages = read_channel_messages(general_channel)
if len(messages) == 0:
    raise ValueError("No messages found in the general channel")

restaurant_lead = query_ai_assistant(
    "Review the following Slack messages from channel {}. Find the message that most likely corresponds to someone writing positively about a great restaurant near the office. Return found=true only if there is a specific matching message. Extract the exact sender and exact body of that message. Identify the restaurant name. Determine what kind of food they serve using the message content if it is stated there; if it is not stated explicitly, use the restaurant name and message context to identify the cuisine if possible. If the message includes a website or URL for the restaurant, extract it; otherwise return an empty string for restaurant_url. If there is no matching message, set found=false and use empty strings for the other fields.\nMessages: {}".format(general_channel, repr(messages)),
    RestaurantLead,
)

if not restaurant_lead.found:
    raise ValueError("Could not find a relevant restaurant message in the general channel")

cuisine = restaurant_lead.cuisine.strip()

if cuisine == "" and restaurant_lead.restaurant_url.strip() != "":
    webpage = get_webpage(restaurant_lead.restaurant_url)
    if webpage is not None:
        cuisine_info = query_ai_assistant(
            "Use the following restaurant webpage content to identify what kind of food the restaurant serves. Return a concise cuisine description.\nRestaurant name: {}\nWebpage content: {}".format(restaurant_lead.restaurant_name, webpage),
            CuisineInfo,
        )
        cuisine = cuisine_info.cuisine.strip()

if cuisine == "":
    cuisine_info = query_ai_assistant(
        "Identify what kind of food this restaurant serves. Use the restaurant name and the Slack message context. Return a concise cuisine description.\nRestaurant name: {}\nSlack message sender: {}\nSlack message body: {}".format(
            restaurant_lead.restaurant_name,
            restaurant_lead.source_sender,
            restaurant_lead.source_body,
        ),
        CuisineInfo,
    )
    cuisine = cuisine_info.cuisine.strip()

users_in_general = get_users_in_channel(general_channel)
bob_matches = [user for user in users_in_general if user.lower() == "bob"]

if len(bob_matches) == 1:
    bob_user = bob_matches[0]
elif len(users_in_general) > 0:
    user_choice = query_ai_assistant(
        "Select the exact Slack user string from the following list that best matches the user's reference to Bob. Return one exact user string from the list.\nUsers: {}".format(repr(users_in_general)),
        UserSelection,
    )
    bob_user = user_choice.user
    if bob_user not in users_in_general:
        bob_user = "Bob"
else:
    bob_user = "Bob"

dm_body = "I found the restaurant recommendation in {}. {} serves {}. Original message from {}: {}".format(
    general_channel,
    restaurant_lead.restaurant_name,
    cuisine,
    restaurant_lead.source_sender,
    restaurant_lead.source_body,
)

send_direct_message(bob_user, dm_body)
print("Sent restaurant cuisine information to {}.".format(bob_user))
```
